import { describe, it, expect } from '@jest/globals';
import { validateSduiJson } from '../sduiLinter';

function lint(json: object | string) {
  const doc = typeof json === 'string' ? json : JSON.stringify(json, null, 2);
  return validateSduiJson(doc);
}

describe('validateSduiJson', () => {
  describe('valid payloads', () => {
    it('returns no diagnostics for a valid minimal screen', () => {
      const result = lint({
        id: 'test-screen',
        body: [
          { type: 'heading', props: { text: 'Hello' } },
        ],
      });
      expect(result).toHaveLength(0);
    });

    it('returns no diagnostics for a full valid screen', () => {
      const result = lint({
        id: 'voucher-form',
        context: { balance: { points: 15000 } },
        header: { type: 'nav_header', props: { title: 'Criar voucher' } },
        body: [
          { type: 'heading', props: { text: 'Defina o valor' } },
          { type: 'text', props: { text: 'Escolha quantos pontos usar', type: 'bodyMD' } },
          { type: 'balance_display', props: { label: 'Saldo', pointsFormatted: '15.000', priceFormatted: 'R$ 150,00' } },
          { type: 'points_input', props: { label: 'Pontos' } },
          { type: 'separator', props: {} },
          { type: 'button', props: { text: 'Continuar' } },
        ],
        footer: { type: 'link', props: { text: 'Regras de uso' } },
      });
      expect(result).toHaveLength(0);
    });

    it('accepts components with visible conditional', () => {
      const result = lint({
        id: 'test',
        body: [
          {
            type: 'button',
            props: { text: 'Submit' },
            visible: { rule: { '>': [{ var: 'form.points' }, 0] } },
          },
        ],
      });
      expect(result).toHaveLength(0);
    });
  });

  describe('structural errors', () => {
    it('reports error for non-object JSON', () => {
      const result = lint('[]');
      expect(result.length).toBeGreaterThan(0);
      expect(result[0].message).toContain('must be a JSON object');
    });

    it('reports error for missing required "id" field', () => {
      const result = lint({ body: [{ type: 'heading', props: { text: 'Hi' } }] });
      expect(result.some(d => d.message.includes('"id"'))).toBe(true);
    });

    it('reports error for missing required "body" field', () => {
      const result = lint({ id: 'test' });
      expect(result.some(d => d.message.includes('"body"'))).toBe(true);
    });

    it('returns empty for invalid JSON (parse linter handles that)', () => {
      const result = lint('{ invalid json }');
      expect(result).toHaveLength(0);
    });
  });

  describe('component type validation', () => {
    it('warns on unknown component type', () => {
      const result = lint({
        id: 'test',
        body: [{ type: 'unknownWidget', props: {} }],
      });
      expect(result.some(d => d.message.includes('Unknown component type "unknownWidget"'))).toBe(true);
    });

    it('suggests similar type for typo "headng"', () => {
      const result = lint({
        id: 'test',
        body: [{ type: 'headng', props: { text: 'Hi' } }],
      });
      const typoWarning = result.find(d => d.message.includes('headng'));
      expect(typoWarning).toBeDefined();
      expect(typoWarning!.message).toContain('did you mean "heading"');
    });

    it('suggests "button" for "buton"', () => {
      const result = lint({
        id: 'test',
        body: [{ type: 'buton', props: { text: 'Click' } }],
      });
      const typoWarning = result.find(d => d.message.includes('buton'));
      expect(typoWarning).toBeDefined();
      expect(typoWarning!.message).toContain('did you mean "button"');
    });
  });

  describe('required props validation', () => {
    it('reports missing required "text" on heading', () => {
      const result = lint({
        id: 'test',
        body: [{ type: 'heading', props: {} }],
      });
      expect(result.some(d => d.message.includes('"heading" requires property "text"'))).toBe(true);
    });

    it('reports missing required props on balance_display', () => {
      const result = lint({
        id: 'test',
        body: [{ type: 'balance_display', props: { label: 'Saldo' } }],
      });
      expect(result.some(d => d.message.includes('"pointsFormatted"'))).toBe(true);
      expect(result.some(d => d.message.includes('"priceFormatted"'))).toBe(true);
    });

    it('reports missing required "items" on list_text_icon', () => {
      const result = lint({
        id: 'test',
        body: [{ type: 'list_text_icon', props: {} }],
      });
      expect(result.some(d => d.message.includes('"items"'))).toBe(true);
    });

    it('reports missing required "icon" and "text" on icon_text_row', () => {
      const result = lint({
        id: 'test',
        body: [{ type: 'icon_text_row', props: {} }],
      });
      expect(result.some(d => d.message.includes('"icon"'))).toBe(true);
      expect(result.some(d => d.message.includes('"text"'))).toBe(true);
    });
  });

  describe('unknown props validation', () => {
    it('warns on unknown prop and suggests "color" for "colour"', () => {
      const result = lint({
        id: 'test',
        body: [{ type: 'heading', props: { text: 'Hi', colour: 'red' } }],
      });
      const warning = result.find(d => d.message.includes('colour'));
      expect(warning).toBeDefined();
      expect(warning!.message).toContain('did you mean "color"');
    });

    it('warns on unknown prop and suggests "disabled" for "disbled"', () => {
      const result = lint({
        id: 'test',
        body: [{ type: 'button', props: { text: 'Go', disbled: true } }],
      });
      const warning = result.find(d => d.message.includes('disbled'));
      expect(warning).toBeDefined();
      expect(warning!.message).toContain('did you mean "disabled"');
    });
  });

  describe('multiple components', () => {
    it('validates all body components independently', () => {
      const result = lint({
        id: 'test',
        body: [
          { type: 'heading', props: {} },
          { type: 'button', props: {} },
          { type: 'unknownType', props: {} },
        ],
      });
      expect(result.some(d => d.message.includes('"heading" requires property "text"'))).toBe(true);
      expect(result.some(d => d.message.includes('"button" requires property "text"'))).toBe(true);
      expect(result.some(d => d.message.includes('Unknown component type "unknownType"'))).toBe(true);
    });
  });
});

