      });
      expect(result.some(d => d.message.includes('Unknown component type "badType"'))).toBe(true);
    });
  });

  describe('edge cases', () => {
    it('accepts empty body array', () => {
      const result = lint({ id: 'test', body: [] });
      expect(result).toHaveLength(0);
    });

    it('treats null prop values as missing for required props', () => {
      const result = lint({
        id: 'test',
        body: [{ type: 'heading', props: { text: null } }],
      });
      expect(result.some(d => d.message.includes('"heading" requires property "text"'))).toBe(true);
    });

    it('accepts JSON5 input with unquoted keys', () => {
      const result = validateSduiJson(`{
        id: "test",
        body: [
          { type: "heading", props: { text: "Hello" } }
        ]
      }`);
      expect(result).toHaveLength(0);
    });
  });
});

